INSERT INTO public.library_content (title, description, type, category, read_time, content) VALUES
('حقوق المرأة في الدستور المصري', 'نظرة شاملة على المواد الدستورية التي تكفل حقوق المرأة وتضمن المساواة بين الجنسين', 'article', 'حقوق', '5 دقائق', 'كفل الدستور المصري الصادر عام 2014 العديد من الحقوق للمرأة، أبرزها المادة 11 التي تنص على التزام الدولة بتحقيق المساواة بين المرأة والرجل في جميع الحقوق المدنية والسياسية والاقتصادية والاجتماعية والثقافية. كما نصت على التزام الدولة باتخاذ التدابير الكفيلة بضمان تمثيل المرأة تمثيلاً مناسباً في المجالس النيابية، وحقها في تولي الوظائف العامة والعليا في الدولة.'),
('كيف تتعامل مع التحرش الإلكتروني؟', 'دليل شامل للتعامل مع حالات التحرش عبر الإنترنت ووسائل التواصل الاجتماعي', 'article', 'توعية رقمية', '4 دقائق', 'التحرش الإلكتروني جريمة يعاقب عليها القانون المصري. إذا تعرضت للتحرش الإلكتروني: 1) احتفظ بالأدلة (لقطات شاشة). 2) لا ترد على المتحرش. 3) قم بحظره والإبلاغ عنه. 4) تواصل مع الوحدة لتقديم بلاغ سري. 5) يمكنك تقديم بلاغ لمباحث الإنترنت. القانون رقم 175 لسنة 2018 بشأن مكافحة جرائم تقنية المعلومات يجرم التحرش الإلكتروني بالحبس والغرامة.'),
('الصحة النفسية للطلاب الجامعيين', 'أهمية الصحة النفسية وكيفية التعامل مع الضغوط الدراسية والاجتماعية', 'article', 'صحة نفسية', '6 دقائق', 'الصحة النفسية جزء أساسي من الصحة العامة. كطالب جامعي، قد تواجه ضغوطاً متعددة. إليك بعض النصائح: 1) نظم وقتك بين الدراسة والراحة. 2) مارس الرياضة بانتظام. 3) تحدث عن مشاعرك مع شخص تثق به. 4) لا تتردد في طلب المساعدة المتخصصة. 5) تجنب العزلة الاجتماعية. الوحدة توفر جلسات دعم نفسي مجانية وسرية لجميع الطلاب.'),
('اتفاقية القضاء على جميع أشكال التمييز ضد المرأة (سيداو)', 'تعرف على أهم المواثيق الدولية لحماية حقوق المرأة', 'article', 'حقوق دولية', '7 دقائق', 'اتفاقية سيداو (CEDAW) هي معاهدة دولية اعتمدتها الجمعية العامة للأمم المتحدة عام 1979. وقعت عليها مصر عام 1981. تُعرف بأنها الوثيقة الدولية لحقوق المرأة. تتضمن 30 مادة تحدد التمييز ضد المرأة وتضع أجندة للعمل الوطني لإنهاء هذا التمييز. تلزم الدول الأطراف بإدماج مبدأ المساواة في أنظمتها القانونية وإلغاء جميع القوانين التمييزية.'),
('دليل الطالب لبيئة جامعية آمنة', 'نصائح عملية للحفاظ على بيئة جامعية صحية وآمنة للجميع', 'article', 'توعية', '3 دقائق', 'بيئة جامعية آمنة هي حق لكل طالب وطالبة. إليك ما يمكنك فعله: 1) احترم زملاءك بغض النظر عن الجنس أو الخلفية. 2) إذا شهدت موقفاً غير لائق، لا تصمت. 3) استخدم نظام الإبلاغ السري للوحدة. 4) شارك في أنشطة التوعية. 5) كن قدوة إيجابية في محيطك. تذكر: السكوت عن الظلم يساهم في استمراره.');
